-- ----------------------------------------------------------------------------
-- vw_users: Application users. Therapists, supervisors, and clients log in via dev-login by user id (email).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_users WITH (security_invoker = ON) AS
SELECT
  t.users_id,                                                                   -- PK: the user's email.
  t.full_name,
  t.role,                                                                       -- therapist | supervisor | client
  calc_users_name(t.users_id) AS name,
  calc_users_client_count(t.users_id) AS client_count
FROM users t;

-- ----------------------------------------------------------------------------
-- vw_clients: People in treatment. Each has an assigned therapist, a set of goals, and a stream of sessions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_clients WITH (security_invoker = ON) AS
SELECT
  t.clients_id,                                                                 -- PK: short slug.
  t.client_name,
  t.therapist,                                                                  -- FK to Users.UsersId.
  calc_clients_therapist_name(t.clients_id) AS therapist_name,
  t.start_date,
  calc_clients_name(t.clients_id) AS name,
  calc_clients_session_count(t.clients_id) AS session_count,
  calc_clients_avg_mood_rating(t.clients_id) AS avg_mood_rating,
  calc_clients_goal_count(t.clients_id) AS goal_count,
  calc_clients_avg_goal_progress(t.clients_id) AS avg_goal_progress,            -- 2nd-order: aggregates Goal.ProgressPct (a calc).
  calc_clients_last_session_label(t.clients_id) AS last_session_label,          -- Most recent session label for this client.
  calc_clients_is_at_risk(t.clients_id) AS is_at_risk,                          -- 3rd-order: low mood OR low avg goal progress.
  calc_clients_status_label(t.clients_id) AS status_label                       -- 4th-order: human-readable client status derived from IsAtRisk.
FROM clients t;

-- ----------------------------------------------------------------------------
-- vw_goals: Treatment goals owned by a client. TargetScore is editable.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_goals WITH (security_invoker = ON) AS
SELECT
  t.goals_id,
  t.title,
  t.client,
  calc_goals_client_name(t.goals_id) AS client_name,
  calc_goals_client_therapist(t.goals_id) AS client_therapist,
  t.target_score,                                                               -- 0-10. EDITABLE.
  calc_goals_name(t.goals_id) AS name,
  calc_goals_update_count(t.goals_id) AS update_count,
  calc_goals_avg_score_achieved(t.goals_id) AS avg_score_achieved,
  calc_goals_latest_score(t.goals_id) AS latest_score,                          -- Best score recorded against this goal.
  calc_goals_progress_pct(t.goals_id) AS progress_pct,                          -- 2nd-order.
  calc_goals_remaining_gap(t.goals_id) AS remaining_gap,                        -- 2nd-order: distance to target.
  calc_goals_is_on_track(t.goals_id) AS is_on_track                             -- 3rd-order.
FROM goals t;

-- ----------------------------------------------------------------------------
-- vw_sessions: Therapy sessions. MoodRating is editable and feeds the client-level rollup.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_sessions WITH (security_invoker = ON) AS
SELECT
  t.sessions_id,
  t.client,
  calc_sessions_client_name(t.sessions_id) AS client_name,
  calc_sessions_client_therapist(t.sessions_id) AS client_therapist,
  t.session_label,
  t.duration_minutes,
  t.mood_rating,                                                                -- 1-10. EDITABLE.
  t.notes,
  calc_sessions_name(t.sessions_id) AS name,
  calc_sessions_update_count(t.sessions_id) AS update_count,                    -- Goal updates recorded this session.
  calc_sessions_avg_score_achieved(t.sessions_id) AS avg_score_achieved,        -- Average update score for this session.
  calc_sessions_is_productive(t.sessions_id) AS is_productive,                  -- 2nd-order: session captured >=2 goal updates AND avg score >=5.
  calc_sessions_status_label(t.sessions_id) AS status_label                     -- 3rd-order: human-readable session status derived from IsProductive.
FROM sessions t;

-- ----------------------------------------------------------------------------
-- vw_goal_updates: Per-session goal progress entries. ScoreAchieved is editable.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_goal_updates WITH (security_invoker = ON) AS
SELECT
  t.goal_updates_id,
  t.goal,
  calc_goal_updates_goal_title(t.goal_updates_id) AS goal_title,
  calc_goal_updates_goal_client(t.goal_updates_id) AS goal_client,
  calc_goal_updates_goal_target_score(t.goal_updates_id) AS goal_target_score,
  calc_goal_updates_goal_client_therapist(t.goal_updates_id) AS goal_client_therapist,
  t."session",
  calc_goal_updates_session_label(t.goal_updates_id) AS session_label,
  t.score_achieved,                                                             -- 0-10. EDITABLE.
  calc_goal_updates_name(t.goal_updates_id) AS name
FROM goal_updates t;

